return (async function () {
  const svg = d3.select(svgElement);
  const plot = svg.select('g[transform]');
  const plotHeight = +svg.attr('data-plot-h');

  const ease = d3.easeCubicInOut;
  const annotationDuration = 700;

  const annotationLayer = plot.select('.annotation-layer').empty()
    ? plot.append('g').attr('class', 'annotation-layer').style('pointer-events', 'none')
    : plot.select('.annotation-layer');

  const visibleBars = plot.selectAll('rect.main-bar')
    .filter(function () {
      return d3.select(this).style('display') !== 'none' &&
             +d3.select(this).style('opacity') !== 0;
    });

  const barData = visibleBars.data().map(d => ({
    company: d.key,
    year: +d.Year
  }));

  const diffValueMap = new Map();
  annotationLayer.selectAll('.diff-bar-value').each(function () {
    const el = d3.select(this);
    const company = el.attr('data-company');
    const diff = +el.attr('data-diff');
    diffValueMap.set(company, diff);
  });

  const companies = Array.from(diffValueMap.keys());
  const minCompany = companies.reduce((a, b) => (diffValueMap.get(a) <= diffValueMap.get(b) ? a : b));
  const maxCompany = companies.reduce((a, b) => (diffValueMap.get(a) >= diffValueMap.get(b) ? a : b));

  const minBarNode = visibleBars.filter(d => d.key === minCompany).node();
  const maxBarNode = visibleBars.filter(d => d.key === maxCompany).node();

  const minBar = d3.select(minBarNode);
  const maxBar = d3.select(maxBarNode);

  const minX = +minBar.attr('x');
  const minY = +minBar.attr('y');
  const minW = +minBar.attr('width');
  const minDiff = diffValueMap.get(minCompany);

  const maxX = +maxBar.attr('x');
  const maxY = +maxBar.attr('y');
  const maxW = +maxBar.attr('width');
  const maxDiff = diffValueMap.get(maxCompany);

  const maxMinusMin = +(maxDiff - minDiff).toFixed(1);
  const redLineY = maxY;
  const diffLabelX = (minX + maxX) / 2;
  const diffLabelY = redLineY - 10;

  annotationLayer
    .selectAll('.third-difference-red-line, .third-difference-arrow-line, .third-difference-label, .third-bar-value-label')
    .remove();

  const defs = svg.select('defs').empty() ? svg.append('defs') : svg.select('defs');
  defs.select('#difference-arrow').remove();

  defs.append('marker')
    .attr('id', 'difference-arrow')
    .attr('viewBox', '0 -5 10 10')
    .attr('refX', 5)
    .attr('refY', 0)
    .attr('markerWidth', 6)
    .attr('markerHeight', 6)
    .attr('orient', 'auto-start-reverse')
    .append('path')
    .attr('d', 'M0,-5L10,0L0,5')
    .attr('fill', 'red');

  const valueLabels = annotationLayer.selectAll('.third-bar-value-label')
    .data([
      { x: minX, y: minY, width: minW, diff: minDiff },
      { x: maxX, y: maxY, width: maxW, diff: maxDiff }
    ])
    .enter()
    .append('text')
    .attr('class', 'third-bar-value-label')
    .attr('x', d => d.x + d.width / 2)
    .attr('y', d => d.y + Math.max(14, Math.min((plotHeight - d.y) / 2, 22)))
    .attr('text-anchor', 'middle')
    .attr('dominant-baseline', 'middle')
    .attr('font-size', 20)
    .attr('font-weight', '600')
    .attr('fill', 'white')
    .style('opacity', 0)
    .text(d => d.diff);

  const redLine = annotationLayer.append('line')
    .attr('class', 'third-difference-red-line')
    .attr('x1', maxX)
    .attr('x2', maxX)
    .attr('y1', redLineY)
    .attr('y2', redLineY)
    .attr('stroke', 'red')
    .attr('stroke-width', 2)
    .style('opacity', 0);

  const arrowLine = annotationLayer.append('line')
    .attr('class', 'third-difference-arrow-line')
    .attr('x1', minX)
    .attr('x2', minX)
    .attr('y1', minY)
    .attr('y2', minY)
    .attr('stroke', 'red')
    .attr('stroke-width', 2)
    .attr('marker-start', 'url(#difference-arrow)')
    .attr('marker-end', 'url(#difference-arrow)')
    .style('opacity', 0);

  const diffLabel = annotationLayer.append('text')
    .attr('class', 'third-difference-label')
    .attr('x', diffLabelX)
    .attr('y', diffLabelY)
    .attr('text-anchor', 'middle')
    .attr('font-size', 18)
    .attr('font-weight', '700')
    .attr('fill', 'black')
    .style('opacity', 0)
    .text(`Difference: ${maxMinusMin}`);

  const transition = svg.transition()
    .duration(annotationDuration)
    .ease(ease);

  valueLabels.transition(transition).style('opacity', 1);
  redLine.transition(transition)
    .style('opacity', 1)
    .attr('x2', minX);
  arrowLine.transition(transition)
    .style('opacity', 1)
    .attr('y2', redLineY);
  diffLabel.transition(transition).style('opacity', 1);

  return transition.end().catch(() => {});
})();

